"use client"

import * as React from "react"
import {
  IconTruck,
  IconTruckLoading,
  IconCircleCheck,
  IconClockHour4,
  IconParkingCircle,
  IconAlertTriangle,
} from "@tabler/icons-react"
import type { ColumnDef } from "@tanstack/react-table"
import {
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  DataTable,
  Gantt,
  type GanttItem,
  type GanttRow,
  Leaderboard,
  type LeaderboardItem,
  Meter,
  ReferenceValue,
  RouteStops,
  type RouteStopItem,
  SegmentedControl,
  Separator,
  StatusBoard,
  type StatusBoardGroup,
  type StatusBoardTone,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@gunjo/ui"

import {
  DAY_END,
  DAY_START,
  DRIVER_HOS,
  HOS_LIMIT,
  LOAD_RANK,
  NOW,
  SELECTED_ROUTE,
  UNASSIGNED_LOADS,
  VEHICLES,
  WORKINGS,
  type Load,
  type VehicleStatus,
} from "./data"

// ── 運行状況 → StatusBoard / Badge のトーンへ写像（色のみに依存しない） ───────
const STATUS_TONE: Record<VehicleStatus, StatusBoardTone> = {
  遅延: "danger",
  集荷中: "info",
  輸送中: "primary",
  待機: "muted",
  配送完了: "success",
}

const STATUS_ICON: Record<VehicleStatus, React.ReactNode> = {
  遅延: <IconAlertTriangle className="size-3.5" aria-hidden />,
  集荷中: <IconTruckLoading className="size-3.5" aria-hidden />,
  輸送中: <IconTruck className="size-3.5" aria-hidden />,
  待機: <IconParkingCircle className="size-3.5" aria-hidden />,
  配送完了: <IconCircleCheck className="size-3.5" aria-hidden />,
}

const GROUP_ORDER = ["大型車", "中型車", "冷凍車", "けん引"] as const

function minutesToLabel(min: number): string {
  const h = Math.floor(min / 60)
  const m = min % 60
  if (h === 0) return `${m}分`
  if (m === 0) return `${h}時間`
  return `${h}時間${m}分`
}

const jpy = new Intl.NumberFormat("ja-JP")

// ── 配車盤（StatusBoard） ──────────────────────────────────────────────────
function VehicleBoard() {
  const groups: StatusBoardGroup[] = GROUP_ORDER.map((g) => ({
    label: g,
    items: VEHICLES.filter((v) => v.group === g).map((v) => ({
      id: v.id,
      label: v.id,
      status: v.status,
      tone: STATUS_TONE[v.status],
      statusIcon: STATUS_ICON[v.status],
      icon: <IconTruck className="size-4" aria-hidden />,
      location: v.location,
      note: `${v.driver}・${v.type}　次：${v.nextPlan}`,
      trailing:
        v.loadRatePct > 0 ? (
          <span className="text-xs font-semibold tabular-nums text-muted-foreground">
            積載 {v.loadRatePct}%
          </span>
        ) : (
          <Badge variant="outline">空車</Badge>
        ),
    })),
  }))

  return (
    <StatusBoard
      groups={groups}
      minTileWidth={232}
      aria-label="車両配車盤（運行状況）"
    />
  )
}

// ── 運送案件 未配車一覧（DataTable） ───────────────────────────────────────
function UnassignedLoads() {
  const [assigned, setAssigned] = React.useState<Record<string, boolean>>({})

  const columns = React.useMemo<ColumnDef<Load>[]>(
    () => [
      {
        accessorKey: "id",
        header: "案件番号",
        cell: ({ row }) => (
          <span className="font-mono text-xs font-semibold tabular-nums">{row.original.id}</span>
        ),
      },
      {
        id: "route",
        header: "集荷地 → 配送地",
        cell: ({ row }) => (
          <div className="min-w-[200px]">
            <div className="text-sm font-medium">{row.original.pickup}</div>
            <div className="text-xs text-muted-foreground">↓ {row.original.dropoff}</div>
          </div>
        ),
      },
      {
        accessorKey: "shipper",
        header: "荷主 / 着荷主",
        cell: ({ row }) => (
          <div className="min-w-[160px] text-xs">
            <div className="font-medium text-foreground">{row.original.shipper}</div>
            <div className="text-muted-foreground">着：{row.original.consignee}</div>
          </div>
        ),
      },
      {
        accessorKey: "item",
        header: "品目",
        cell: ({ row }) => <span className="text-xs">{row.original.item}</span>,
      },
      {
        accessorKey: "weightKg",
        header: "重量 / 容積",
        cell: ({ row }) => (
          <span className="whitespace-nowrap text-xs tabular-nums">
            {jpy.format(row.original.weightKg)}kg
            <span className="text-muted-foreground"> / {row.original.volumeM3}m³</span>
          </span>
        ),
      },
      {
        accessorKey: "needs",
        header: "必要車格",
        cell: ({ row }) => <Badge variant="secondary">{row.original.needs}</Badge>,
      },
      {
        accessorKey: "windowLabel",
        header: "指定時間",
        cell: ({ row }) => {
          const u = row.original.urgency
          return (
            <div className="min-w-[150px]">
              <div className="text-xs">{row.original.windowLabel}</div>
              <Badge
                variant={u === "時間厳守" ? "warning" : u === "余裕" ? "outline" : "info"}
                className="mt-1"
              >
                {u}
              </Badge>
            </div>
          )
        },
      },
      {
        accessorKey: "fare",
        header: "運賃 / 距離",
        cell: ({ row }) => (
          <span className="whitespace-nowrap text-xs tabular-nums">
            ¥{jpy.format(row.original.fare)}
            <span className="text-muted-foreground"> / {row.original.distanceKm}km</span>
          </span>
        ),
      },
      {
        id: "assign",
        header: "配車",
        cell: ({ row }) => {
          const done = assigned[row.original.id]
          return done ? (
            <Badge variant="success" icon={<IconCircleCheck className="size-3.5" aria-hidden />}>
              配車済
            </Badge>
          ) : (
            <Button
              size="sm"
              variant="primary"
              onClick={() => setAssigned((s) => ({ ...s, [row.original.id]: true }))}
            >
              車両を割当
            </Button>
          )
        },
      },
    ],
    [assigned],
  )

  return (
    <DataTable
      columns={columns}
      data={UNASSIGNED_LOADS}
      filter={{ columnId: "shipper", placeholder: "荷主名で絞り込み…" }}
      pageSize={10}
      labels={{
        filterPlaceholder: "荷主名で絞り込み…",
        noResults: "該当する未配車案件はありません",
        rowsPerPage: "表示件数",
        paginationSummary: (from, to, total) => `${total}件中 ${from}–${to}件`,
      }}
    />
  )
}

// ── 車両運用 行路（Gantt / intraday・resolution="hour"） ─────────────────────
function DayWorkings() {
  const rows: GanttRow[] = WORKINGS.map((w) => ({
    id: w.vehicleId,
    label: w.label,
    sublabel: w.sublabel,
  }))

  const items: GanttItem[] = WORKINGS.map((w) => {
    const first = w.segments[0]
    const last = w.segments[w.segments.length - 1]
    return {
      id: `${w.vehicleId}-duty`,
      rowId: w.vehicleId,
      start: `2026-06-29T${first.start}`,
      end: `2026-06-29T${last.end}`,
      label: `${w.label} 行路`,
      tone: "default",
      ariaLabel: `${w.label} ${w.sublabel} 当日行路 ${first.start}〜${last.end}`,
      segments: w.segments.map((s) => ({
        start: `2026-06-29T${s.start}`,
        end: `2026-06-29T${s.end}`,
        tone: s.tone,
        label: s.label,
        kind: s.kind,
      })),
    }
  })

  return (
    <div className="overflow-x-auto">
      <Gantt
        rows={rows}
        items={items}
        startDate={DAY_START}
        endDate={DAY_END}
        today={NOW}
        resolution="hour"
        hourWidth={56}
        hourStep={1}
        rowLabelWidth={132}
        laneHeight={34}
        label="当日 車両運用 行路（出庫→集荷→輸送→配送→帰庫）"
      />
    </div>
  )
}

// ── 配送ルート 立寄り（RouteStops） ────────────────────────────────────────
function DeliveryRoute() {
  const stops: RouteStopItem[] = SELECTED_ROUTE.stops.map((s) => ({
    id: s.id,
    title: s.title,
    description: s.description,
    status: s.status,
    plannedTime: s.plannedTime,
    actualTime: s.actualTime,
    meta: s.meta,
  }))

  return (
    <Card>
      <CardHeader className="p-4 pb-2">
        <CardTitle as="h3" className="text-base">
          {SELECTED_ROUTE.vehicleId}　{SELECTED_ROUTE.label}
        </CardTitle>
        <p className="text-xs text-muted-foreground">乗務員：{SELECTED_ROUTE.driver}　/　予定 vs 実績</p>
      </CardHeader>
      <CardContent className="p-4 pt-2">
        <RouteStops
          stops={stops}
          timeLabels={{ planned: "予定", actual: "実績" }}
          aria-label={`${SELECTED_ROUTE.vehicleId} 配送ルート 立寄り順`}
        />
      </CardContent>
    </Card>
  )
}

// ── 拘束時間 / 改善基準告示 監視（Meter + ReferenceValue） ───────────────────
function HosCompliance() {
  return (
    <div className="flex flex-col gap-3">
      <p className="text-xs text-muted-foreground">
        改善基準告示（トラック）：連続運転 4時間ごとに 30分以上の中断、1日の拘束時間 原則13時間（最大16時間）。
        09:48 時点。
      </p>
      <ul role="list" className="flex flex-col gap-3">
        {DRIVER_HOS.map((d) => {
          // 連続運転：基準（240分=4h）超過で要中断。flagValue で色のみに依存しない判定。
          const contFlag = (
            <ReferenceValue
              value={d.continuousMin}
              range={{ high: HOS_LIMIT.continuousWarn, criticalHigh: HOS_LIMIT.continuousMax }}
              format={(v) => minutesToLabel(v)}
              showLabel
              labels={{
                normal: "余裕あり",
                high: "まもなく中断",
                "critical-high": "中断必須(4h超)",
              }}
            />
          )
          const dutyOver = d.dutyMin >= HOS_LIMIT.dutyStdMax
          return (
            <li
              key={d.driverId}
              className="rounded-md border border-border bg-card p-3"
            >
              <div className="flex flex-wrap items-center justify-between gap-2">
                <div className="flex items-center gap-2">
                  <IconClockHour4 className="size-4 text-muted-foreground" aria-hidden />
                  <span className="font-medium">{d.driver}</span>
                  <Badge variant="outline">{d.vehicleId}</Badge>
                </div>
                {contFlag}
              </div>
              <div className="mt-2 grid gap-3 sm:grid-cols-2">
                <div>
                  <div className="mb-1 flex items-center justify-between text-xs text-muted-foreground">
                    <span>連続運転時間</span>
                    <span className="tabular-nums">{minutesToLabel(d.continuousMin)} / 4時間</span>
                  </div>
                  <Meter
                    value={d.continuousMin}
                    max={HOS_LIMIT.continuousMax}
                    thresholds={{ warning: HOS_LIMIT.continuousWarn / HOS_LIMIT.continuousMax, over: 1 }}
                    formatValue={(v) => minutesToLabel(Math.round(v))}
                    label={`${d.driver} 連続運転時間`}
                    showValue={false}
                  />
                  <p className="mt-1 text-xs text-muted-foreground">{d.sinceBreakLabel}</p>
                </div>
                <div>
                  <div className="mb-1 flex items-center justify-between text-xs text-muted-foreground">
                    <span>当日 拘束時間</span>
                    <span className={dutyOver ? "tabular-nums text-warning" : "tabular-nums"}>
                      {minutesToLabel(d.dutyMin)} / 13時間
                    </span>
                  </div>
                  <Meter
                    value={d.dutyMin}
                    max={HOS_LIMIT.dutyHardMax}
                    target={HOS_LIMIT.dutyStdMax}
                    thresholds={{
                      warning: HOS_LIMIT.dutyStdMax / HOS_LIMIT.dutyHardMax,
                      over: 1,
                    }}
                    formatValue={(v) => minutesToLabel(Math.round(v))}
                    label={`${d.driver} 当日拘束時間`}
                    showValue={false}
                  />
                  <p className="mt-1 text-xs text-muted-foreground">
                    運転 {minutesToLabel(d.drivingMin)}　/　基準線=13時間
                  </p>
                </div>
              </div>
            </li>
          )
        })}
      </ul>
    </div>
  )
}

// ── 積載率ランキング（Leaderboard） ───────────────────────────────────────
function LoadRanking() {
  const items: LeaderboardItem[] = LOAD_RANK.map((r) => ({
    id: r.vehicleId,
    label: r.vehicleId,
    sublabel: r.driver,
    value: r.loadRatePct,
    valueLabel: `${r.loadRatePct}%`,
    delta: r.deltaPct,
    deltaLabel: `${r.deltaPct > 0 ? "+" : ""}${r.deltaPct}pt`,
    tone: r.loadRatePct === 0 ? "muted" : r.loadRatePct >= 85 ? "success" : "primary",
  }))

  return (
    <Leaderboard
      items={items}
      label="本日 車両別 積載率ランキング"
      max={100}
      highlightTop={3}
    />
  )
}

// ── 全体タブ構成 ───────────────────────────────────────────────────────────
type View = "board" | "loads" | "workings"

export function TruckDispatchConsole() {
  const [view, setView] = React.useState<View>("board")

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <SegmentedControl
          aria-label="配車ビュー切替"
          value={view}
          onValueChange={(v) => setView(v as View)}
          options={[
            { value: "board", label: "配車盤", icon: <IconTruck className="size-4" aria-hidden /> },
            { value: "loads", label: "未配車案件", icon: <IconTruckLoading className="size-4" aria-hidden /> },
            { value: "workings", label: "車両運用 行路", icon: <IconClockHour4 className="size-4" aria-hidden /> },
          ]}
        />
        <span className="text-xs text-muted-foreground">
          稼働 {VEHICLES.filter((v) => v.status !== "待機").length} / {VEHICLES.length} 台
        </span>
      </div>

      {view === "board" ? (
        <section aria-labelledby="board-h" className="flex flex-col gap-3">
          <h2 id="board-h" className="text-sm font-semibold text-muted-foreground">
            配車盤 — 運行状況・現在地・積載率
          </h2>
          <VehicleBoard />
        </section>
      ) : null}

      {view === "loads" ? (
        <section aria-labelledby="loads-h" className="flex flex-col gap-3">
          <h2 id="loads-h" className="text-sm font-semibold text-muted-foreground">
            運送案件（未配車） — 荷主・経路・車格・指定時間・運賃
          </h2>
          <UnassignedLoads />
        </section>
      ) : null}

      {view === "workings" ? (
        <section aria-labelledby="workings-h" className="flex flex-col gap-3">
          <h2 id="workings-h" className="text-sm font-semibold text-muted-foreground">
            車両運用 行路（当日・時間軸＝1時間刻み） — 出庫→集荷→輸送→配送→帰庫
          </h2>
          <DayWorkings />
        </section>
      ) : null}

      <Separator />

      {/* 下段：ルート・改善基準・ランキングは常設（タブとは独立に監視したい） */}
      <Tabs defaultValue="route" className="border-0">
        <TabsList>
          <TabsTrigger value="route">配送ルート（立寄り）</TabsTrigger>
          <TabsTrigger value="hos">拘束時間 / 改善基準</TabsTrigger>
          <TabsTrigger value="rank">積載率ランキング</TabsTrigger>
        </TabsList>
        <TabsContent value="route" className="px-0">
          <DeliveryRoute />
        </TabsContent>
        <TabsContent value="hos" className="px-0">
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h3" className="text-base">
                拘束時間 / 改善基準告示 監視
              </CardTitle>
            </CardHeader>
            <CardContent className="p-4 pt-2">
              <HosCompliance />
            </CardContent>
          </Card>
        </TabsContent>
        <TabsContent value="rank" className="px-0">
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h3" className="text-base">
                車両別 積載率ランキング
              </CardTitle>
            </CardHeader>
            <CardContent className="p-4 pt-2">
              <LoadRanking />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  )
}
